// // This module performs a bitwise XOR operation on a 6-bit input, x, based on a 4-bit control signal. The most significant 2 bits of the 12-bit output are hardcoded to `10`, while the next 4 bits are set to an unknown value. The actual operation is determined by the bits 3 to 1 of the `control` input, with the least significant bit indicating whether to perform an AND or OR operation.
module top_module(
	input [5:0] x,
   input [3:0] shift,
   output reg [11:0] out
   );integer i;

always @(*) begin
	out[11:10] = 2'b10;
	out[9:6] = 4'bx;
	i = shift[3:1];
	case (shift[0])
		1'b0: out[5:0] = x << i;
		1'b1: out[5:0] = x >> i;
	endcase
end

endmodule
